   * @throws IllegalArgumentException if only one of [dropOffLat] and [dropOffLon] is provided
   */
  context(service: Service)
  public suspend fun getRealtimeBookings(
    pickupLat: Double,
    pickupLon: Double,
    dropOffLat: Double? = null,
    dropOffLon: Double? = null,
    brandIds: List<String> = emptyList(),
    pickupAddress: String? = null,
    dropOffAddress: String? = null,
  ): Result<GofsFeedResponse<RealtimeBookings>> {
    require(
      dropOffLat == null && dropOffLon == null || (dropOffLat != null && dropOffLon != null)
    ) {
      "Both dropOffLat and dropOffLon must be provided together"
    }

    val url =
      runSuspendCatching {
          URLBuilder(service.feeds.getValue(FeedType.RealtimeBookings)).apply {
            parameters.append("pickup_lat", pickupLat.toString())
            parameters.append("pickup_lon", pickupLon.toString())

            if (dropOffLat != null && dropOffLon != null) {
              parameters.append("drop_off_lat", dropOffLat.toString())
              parameters.append("drop_off_lon", dropOffLon.toString())
            }

            if (brandIds.isNotEmpty()) {
              val joined = brandIds.joinToString(",")
              parameters.append("brand_id", joined)
            }

            if (pickupAddress != null) parameters.append("pickup_address", pickupAddress)
            if (dropOffAddress != null) parameters.append("drop_off_address", dropOffAddress)
          }
        }
        .getOrElse { return Result.failure(it) }

    return getFeedResponse(url.build())
  }

  override fun close(): Unit = httpClient.close()
}

